export class AppComponent implements OnInit {
  trackLibrary: Song[] = [];
  selectedSong: Song | null = null;
  secretMessage: string = '';
  extractedVaultText: string = '';
  searchQuery: string = ''; // New variable to track our typed filter
  @ViewChild('audioPlayer') audioPlayerRef?: ElementRef<HTMLAudioElement>;
  private audioContext: AudioContext | null = null;
  private audioBuffer: AudioBuffer | null = null;
  private audioSource: AudioBufferSourceNode | null = null;
  private playbackOffset = 0;
  private playbackStartTime = 0;
  private playbackState: 'stopped' | 'playing' | 'paused' = 'stopped';

  private backendUrl = '/api';

  constructor(private http: HttpClient) {}

  private get audioPlayer(): HTMLAudioElement | null {
    return this.audioPlayerRef?.nativeElement ?? null;
  }

  ngOnInit(): void {
    this.loadTracks();
  }

  // Getter method that filters tracks dynamically based on title matches
  get filteredTracks(): Song[] {
    if (!this.searchQuery.trim()) {
      return this.trackLibrary;
    }
    return this.trackLibrary.filter(song =>
      song.title.toLowerCase().includes(this.searchQuery.toLowerCase())
    );
  }

  loadTracks() {
    this.http.get<Song[]>(`${this.backendUrl}/songs`).subscribe({
      next: (data) => this.trackLibrary = data,
      error: (err) => console.error('Error connecting to Java backend API:', err)
    });
  }

  playSong(song: Song) {
    this.selectedSong = song;
    this.playTrack(song, 0).catch((err) => console.error('Browser playback failed:', err));
  }

  pausePlayback() {
    if (this.playbackState !== 'playing' || !this.audioContext || !this.audioSource) {
      return;
    }

    this.audioSource.stop();
    this.playbackOffset += this.audioContext.currentTime - this.playbackStartTime;
    this.playbackState = 'paused';
  }

  resumePlayback() {
    if (!this.selectedSong || !this.audioBuffer || this.playbackState !== 'paused') {
      return;
    }

    this.playTrack(this.selectedSong, this.playbackOffset).catch((err) => console.error('Browser resume failed:', err));
  }

  stopPlayback() {
    if (this.audioSource) {
      this.audioSource.stop();
    }

    this.audioSource = null;
    this.audioBuffer = null;
    this.playbackOffset = 0;
    this.playbackStartTime = 0;
    this.playbackState = 'stopped';
  }

  private async playTrack(song: Song, offsetSeconds: number): Promise<void> {
    if (!this.audioContext) {
      this.audioContext = new AudioContext();
    }

    await this.audioContext.resume();

    if (!this.audioBuffer || this.selectedSong?.id !== song.id) {
      const response = await fetch(song.streamUrl);
      const audioData = await response.arrayBuffer();
      this.audioBuffer = await this.audioContext.decodeAudioData(audioData.slice(0));
    }

    if (this.audioSource) {
      try {
        this.audioSource.stop();
      } catch {
        // Ignore a source that already finished or was cleared.
      }
    }

    const sourceNode = this.audioContext.createBufferSource();
    sourceNode.buffer = this.audioBuffer;
    sourceNode.connect(this.audioContext.destination);
    sourceNode.start(0, offsetSeconds);

    this.audioSource = sourceNode;
    this.playbackStartTime = this.audioContext.currentTime - offsetSeconds;
    this.playbackOffset = offsetSeconds;
    this.playbackState = 'playing';

    sourceNode.onended = () => {
      if (this.playbackState === 'playing') {
        this.playbackState = 'stopped';
        this.playbackOffset = 0;
        this.playbackStartTime = 0;
        this.audioSource = null;
      }
    };
  }

  // Steganography: Hides message using the new Java POST handler
  injectMessage() {
    if (!this.selectedSong) {
      alert('⚠️ Please select a song from the directory first!');
      return;
    }
    if (!this.secretMessage.trim()) {
      alert('⚠️ Please type a message payload to hide!');
      return;
    }

    this.http.post(`${this.backendUrl}/stegano/hide?id=${this.selectedSong.id}`, this.secretMessage, { responseType: 'text' })
      .subscribe({
        next: () => {
          alert(`🔒 Secret payload safely injected into: ${this.selectedSong?.title}`);
          this.secretMessage = ''; // Reset input text block
        },
        error: (err) => console.error('Injection link bottleneck:', err)
      });
  }

  // Steganography: Extracts and displays hidden text strings
  extractMessage() {
    if (!this.selectedSong) {
      alert('⚠️ Please select a song from the directory first!');
      return;
    }

    this.http.get(`${this.backendUrl}/stegano/extract?id=${this.selectedSong.id}`, { responseType: 'text' })
      .subscribe({
        next: (data) => {
          this.extractedVaultText = data; // Assigns text to show on screen
        },
        error: (err) => console.error('Extraction link bottleneck:', err)
      });
  }
}
